// Load roster.yml. Extract active team members with discord_id and name.
// NO approval gate for F-17 — this is intentional per spec.
const fs = require('fs');
const yaml = require('js-yaml');
const path = process.env.ROSTER_CONFIG_PATH || '/data/roster.yml';
let roster;
try {
  roster = yaml.load(fs.readFileSync(path, 'utf8'));
} catch (e) {
  throw new Error('Dev DM Listener: cannot load roster.yml: ' + e.message);
}
const activeTeam = (roster.team || []).filter(m => m.active !== false);
return [{
  json: {
    active_team: activeTeam,
    roster_names: activeTeam.map(m => m.name).concat([roster.team_lead.name])
  }
}];

// Expand active_team into individual items for SplitInBatches.
const rosterData = $json;
return rosterData.active_team.map(m => ({
  json: {
    developer_discord_id: m.discord_id,
    developer_name: m.name,
    roster_names: rosterData.roster_names
  }
}));

// Cache the DM channel ID in project_memory for reuse.
const dmResult = $input.first().json;
const devData = $node['For Each Developer (Split)'].json;

if (dmResult.error || !dmResult.id) {
  // Cannot open DM — log and skip this developer
  return [{ json: { skip: true, reason: 'Cannot open DM: ' + (dmResult.error || 'no id'), developer_discord_id: devData.developer_discord_id } }];
}

return [{
  json: {
    skip: false,
    dm_channel_id: dmResult.id,
    developer_discord_id: devData.developer_discord_id,
    developer_name: devData.developer_name,
    roster_names: devData.roster_names,
    cursor_key: 'dev_dm_last_msg_' + devData.developer_discord_id
  }
}];

// Read cursor and prepare for Discord API call.
const cursorRow = $input.first().json;
const dmData = $node['Extract DM Channel ID'].json;
const lastMsgId = cursorRow && cursorRow.value_json ? cursorRow.value_json : null;
const afterParam = lastMsgId ? `&after=${lastMsgId}` : '';
return [{ json: {
  ...dmData,
  last_msg_id: lastMsgId,
  after_param: afterParam
}}];

// Filter to messages from the developer (not from bot).
// Bot messages are identified by matching bot_discord_id stored in project_memory.
// For safety: filter to messages where author.id == developer_discord_id.
const messages = $input.first().json;
const devData = $node['Prepare Fetch Parameters'].json;

if (!Array.isArray(messages) || messages.length === 0) {
  return [];
}

const devId = devData.developer_discord_id;
const devMessages = messages.filter(m => m.author && m.author.id === devId);

if (devMessages.length === 0) return [];

const highestId = devMessages.map(m => m.id).reduce((a, b) => a > b ? a : b, devMessages[0].id);

return devMessages.map(m => ({
  json: {
    message_id: m.id,
    message_content: m.content,
    dm_channel_id: devData.dm_channel_id,
    developer_discord_id: devData.developer_discord_id,
    developer_name: devData.developer_name,
    roster_names: devData.roster_names,
    cursor_key: devData.cursor_key,
    highest_id: highestId
  }
}));

// Classify message: !mute, !unmute, !explain, !approve, !reject, !edit, or Q&A.
const content = ($json.message_content || '').trim();
const lower = content.toLowerCase();
let type;
if (lower === '!mute') {
  type = 'mute';
} else if (lower === '!unmute') {
  type = 'unmute';
} else if (lower.startsWith('!explain')) {
  type = 'explain';
} else if (lower.startsWith('!approve ')) {
  type = 'approve';
} else if (lower.startsWith('!reject ')) {
  type = 'reject';
} else if (lower.startsWith('!edit ')) {
  type = 'edit';
} else {
  type = 'qa';
}
return [{ json: { ...$json, message_type: type } }];

// Transparency handler (SC-13): explain what the agent did.
// Only return information relevant to this developer's own data.
const content = ($json.message_content || '').trim();
const subject = content.replace(/^!explain\s*/i, '').trim();
return [{ json: { ...$json, explain_subject: subject } }];

// Build explanation using only this developer's own data (SC-13).
// Third-party individual data must not be exposed.
const devData = $node['Explain Handler — Parse Subject'].json;
const subject = devData.explain_subject.toLowerCase();
const devId = devData.developer_discord_id;
const logs = $input.all();

// Filter to logs involving this developer only
const matching = logs.filter(item => {
  const v = typeof item.json.value_json === 'string' ? JSON.parse(item.json.value_json) : item.json.value_json;
  const keyMatches = (item.json.key || '').toLowerCase().includes(subject);
  const bodyMatches = JSON.stringify(v).toLowerCase().includes(subject);
  // Only include if it's a dev_dm log for this developer OR a general log (no individual_id that differs)
  const isThisDev = v.developer_discord_id && v.developer_discord_id === devId;
  return (keyMatches || bodyMatches) && isThisDev;
});

let explanation;
if (matching.length === 0) {
  explanation = `No recent actions found matching '${devData.explain_subject}'. I have not logged any action with that description recently.`;
} else {
  const lines = matching.map(item => {
    const v = typeof item.json.value_json === 'string' ? JSON.parse(item.json.value_json) : item.json.value_json;
    return `- Action: ${v.action || 'unknown'} | At: ${v.timestamp || 'n/a'}`;
  });
  explanation = `Here is what I did related to '${devData.explain_subject}':\n${lines.join('\n')}\n\nI do not include information about other team members in this explanation. (SC-13)`;
}

return [{ json: { explanation, dm_channel_id: devData.dm_channel_id } }];

// Q&A Handler: build Ollama request.
// System prompt is verbatim from the planner. No approval gate (F-17).
const data = $json;

const systemPrompt = `You are a project coordination assistant helping a team member understand their project. Answer questions with project-level context.

MANDATORY RULES:
1. Do not name or attribute information to any individual team member other than the person asking. The person asking may receive information about their own work area.
2. Do not disclose what other team members are working on in an attributed way.
3. If the question asks who specifically is assigned to a work area, provide the work-area context without naming individuals (per SC-03).
4. Do not produce productivity scores, commit counts attributed to individuals, or hours attributed to individuals.
5. If you do not know the answer, say so honestly. Do not fabricate.
6. Keep the response concise — under 200 words.

The person asking is: ${data.developer_name}. You may use their name and reference their own work area specifically.`;

const userMessage = `Developer question: ${data.message_content}\nProject context: No stored project context available.`;

const llmRequest = {
  model: 'llama3',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ],
  temperature: 0.3,
  stream: false
};

return [{ json: { ...data, llm_request: llmRequest } }];

// Extract answer and apply privacy validation.
// Redact other roster members' names. Allow requesting developer's own name through.
const result = $input.first().json;
const data = $node['Q&A Handler — Build LLM Prompt'].json;
const rosterNames = data.roster_names || [];
const developerName = data.developer_name;

let answerText = "I'm temporarily unable to answer — the reasoning service is offline. Please try again shortly.";
if (!result.error && result.choices && result.choices[0]) {
  answerText = result.choices[0].message.content || answerText;
}

// Privacy validation: redact other names, keep developer's own name
for (const name of rosterNames) {
  if (!name || name === developerName) continue; // Keep requester's own name
  const escapedName = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`\\b${escapedName}\\b`, 'gi');
  answerText = answerText.replace(regex, '[team member]');
}

return [{ json: {
  reply_text: answerText,
  dm_channel_id: data.dm_channel_id,
  developer_discord_id: data.developer_discord_id,
  message_id: data.message_id
}}];

// !approve <draft_id> — parse draft ID from message.
const parts = $json.message_content.trim().split(/\s+/);
const draftId = parts[1];
if (!draftId || !/^[0-9a-f-]{36}$/.test(draftId)) {
  return [{ json: { ...$json, parse_error: 'Invalid or missing draft ID. Usage: !approve <draft_id>' } }];
}
return [{ json: { ...$json, draft_id: draftId, parse_error: null } }];

// Validate approve — check draft exists, pending, correct approver, not expired, type=time_entry.
const draft = $input.first().json;
const devId = $node['Approve — Parse Draft ID'].json.developer_discord_id;
if (!draft || !draft.id) return [{ json: { ...$node['Approve — Parse Draft ID'].json, valid: false, reason: 'Draft not found.' } }];
if (draft.status !== 'pending') return [{ json: { ...$node['Approve — Parse Draft ID'].json, valid: false, reason: 'Draft is not pending (status: ' + draft.status + ').' } }];
if (draft.approver_discord_id !== devId) return [{ json: { ...$node['Approve — Parse Draft ID'].json, valid: false, reason: 'You are not the approver for this draft.' } }];
if (new Date(draft.expires_at) < new Date()) return [{ json: { ...$node['Approve — Parse Draft ID'].json, valid: false, reason: 'Draft has expired.' } }];
if (draft.type !== 'time_entry') return [{ json: { ...$node['Approve — Parse Draft ID'].json, valid: false, reason: 'This command only works for time entry drafts.' } }];
const contentJson = typeof draft.content_json === 'string' ? JSON.parse(draft.content_json) : draft.content_json;
return [{ json: { ...$node['Approve — Parse Draft ID'].json, valid: true, draft_type: draft.type, content_json: contentJson } }];

// !reject <draft_id> — parse draft ID from message.
const parts = $json.message_content.trim().split(/\s+/);
const draftId = parts[1];
if (!draftId || !/^[0-9a-f-]{36}$/.test(draftId)) {
  return [{ json: { ...$json, parse_error: 'Invalid or missing draft ID. Usage: !reject <draft_id>' } }];
}
return [{ json: { ...$json, draft_id: draftId, parse_error: null } }];

// Validate reject — same checks as approve.
const draft = $input.first().json;
const devId = $node['Reject — Parse Draft ID'].json.developer_discord_id;
if (!draft || !draft.id) return [{ json: { ...$node['Reject — Parse Draft ID'].json, valid: false, reason: 'Draft not found.' } }];
if (draft.status !== 'pending') return [{ json: { ...$node['Reject — Parse Draft ID'].json, valid: false, reason: 'Draft is not pending (status: ' + draft.status + ').' } }];
if (draft.approver_discord_id !== devId) return [{ json: { ...$node['Reject — Parse Draft ID'].json, valid: false, reason: 'You are not the approver for this draft.' } }];
if (new Date(draft.expires_at) < new Date()) return [{ json: { ...$node['Reject — Parse Draft ID'].json, valid: false, reason: 'Draft has expired.' } }];
if (draft.type !== 'time_entry') return [{ json: { ...$node['Reject — Parse Draft ID'].json, valid: false, reason: 'This command only works for time entry drafts.' } }];
return [{ json: { ...$node['Reject — Parse Draft ID'].json, valid: true } }];

// !edit <draft_id> <revised description> — parse from message.
const content = $json.message_content.trim();
const parts = content.split(/\s+/);
const draftId = parts[1];
const revisedText = parts.slice(2).join(' ').trim();
if (!draftId || !/^[0-9a-f-]{36}$/.test(draftId)) {
  return [{ json: { ...$json, parse_error: 'Missing or invalid draft ID. Usage: !edit <draft_id> <new description>' } }];
}
if (!revisedText) {
  return [{ json: { ...$json, parse_error: 'Missing revised description. Usage: !edit <draft_id> <new description>' } }];
}
return [{ json: { ...$json, draft_id: draftId, revised_description: revisedText, parse_error: null } }];

// Validate edit — same checks as approve.
const draft = $input.first().json;
const parseData = $node['Edit — Parse Draft ID and Description'].json;
const devId = parseData.developer_discord_id;
if (!draft || !draft.id) return [{ json: { ...parseData, valid: false, reason: 'Draft not found.' } }];
if (draft.status !== 'pending') return [{ json: { ...parseData, valid: false, reason: 'Draft is not pending (status: ' + draft.status + ').' } }];
if (draft.approver_discord_id !== devId) return [{ json: { ...parseData, valid: false, reason: 'You are not the approver for this draft.' } }];
if (new Date(draft.expires_at) < new Date()) return [{ json: { ...parseData, valid: false, reason: 'Draft has expired.' } }];
if (draft.type !== 'time_entry') return [{ json: { ...parseData, valid: false, reason: 'This command only works for time entry drafts.' } }];
const contentJson = typeof draft.content_json === 'string' ? JSON.parse(draft.content_json) : draft.content_json;
return [{ json: { ...parseData, valid: true, content_json: contentJson } }];

// Merge updated content_json from RETURNING row with edit parse data for WF13 call.
const returning = $input.first().json;
const parseData = $node['Edit — Parse Draft ID and Description'].json;
const contentJson = typeof returning.content_json === 'string'
  ? JSON.parse(returning.content_json)
  : (returning.content_json || $node['Edit — Validate Draft'].json.content_json);
// Ensure description in metadata is updated
if (contentJson && contentJson.metadata) {
  contentJson.metadata.description = parseData.revised_description;
}
return [{ json: { ...parseData, content_json: contentJson, draft_id: parseData.draft_id } }];
